 37→class FilteredDeckOptions :
 38→    AppCompatPreferenceActivity<FilteredDeckOptions.DeckPreferenceHack>(),
 39→    SharedPreferences.OnSharedPreferenceChangeListener {
 40→    private var allowCommit = true
 41→
 42→    // TODO: not anymore used in libanki?
 43→    private val dynExamples = arrayOf(
 44→        null,
 45→        "{'search'=\"is:new\", 'resched'=False, 'steps'=\"1\", 'order'=5}",
 46→        "{'search'=\"added:1\", 'resched'=False, 'steps'=\"1\", 'order'=5}",
 47→        "{'search'=\"rated:1:1\", 'order'=4}",
 48→        "{'search'=\"prop:due<=2\", 'order'=6}",
 49→        "{'search'=\"is:due tag:TAG\", 'order'=6}",
 50→        "{'search'=\"is:due\", 'order'=3}",
 51→        "{'search'=\"\", 'steps'=\"1 10 20\", 'order'=0}"
 52→    )
 53→
 54→    inner class DeckPreferenceHack : AppCompatPreferenceActivity<FilteredDeckOptions.DeckPreferenceHack>.AbstractPreferenceHack() {
 55→        var secondFilter = false
 56→        override fun cacheValues() {
 57→            Timber.d("cacheValues()")
 58→            val ar = deck.getJSONArray("terms").getJSONArray(0)
 59→            secondFilter = deck.getJSONArray("terms").length() > 1
 60→            val ar2: JSONArray?
 61→            values["search"] = ar.getString(0)
 62→            values["limit"] = ar.getString(1)
 63→            values["order"] = ar.getString(2)
 64→            if (secondFilter) {
 65→                ar2 = deck.getJSONArray("terms").getJSONArray(1)
 66→                values["search_2"] = ar2.getString(0)
 67→                values["limit_2"] = ar2.getString(1)
 68→                values["order_2"] = ar2.getString(2)
 69→            }
 70→            val delays = deck.optJSONArray("delays")
 71→            if (delays != null) {
 72→                values["steps"] = convertFromJSON(delays)
 73→                values["stepsOn"] = java.lang.Boolean.toString(true)
 74→            } else {
 75→                values["steps"] = "1 10"
 76→                values["stepsOn"] = java.lang.Boolean.toString(false)
 77→            }
 78→            values["resched"] = java.lang.Boolean.toString(deck.getBoolean("resched"))
 79→        }
 80→
 81→        inner class Editor : AppCompatPreferenceActivity<FilteredDeckOptions.DeckPreferenceHack>.AbstractPreferenceHack.Editor() {
 82→            override fun commit(): Boolean {
 83→                Timber.d("commit() changes back to database")
 84→                for ((key, value) in update.valueSet()) {
 85→                    Timber.i("Change value for key '%s': %s", key, value)
 86→                    val ar = deck.getJSONArray("terms")
 87→                    if (pref.secondFilter) {
 88→                        when (key) {
 89→                            "search_2" -> {
 90→                                ar.getJSONArray(1).put(0, value)
 91→                            }
 92→                            "limit_2" -> {
 93→                                ar.getJSONArray(1).put(1, value)
 94→                            }
 95→                            "order_2" -> {
 96→                                ar.getJSONArray(1).put(2, (value as String).toInt())
 97→                            }
 98→                        }
 99→                    }
100→                    when (key) {
101→                        "search" -> {
102→                            ar.getJSONArray(0).put(0, value)
103→                        }
104→
105→                        "limit" -> {
106→                            ar.getJSONArray(0).put(1, value)
107→                        }
108→                        "order" -> {
109→                            ar.getJSONArray(0).put(2, (value as String).toInt())
110→                        }
111→                        "resched" -> {
112→                            deck.put("resched", value)
113→                        }
114→                        "stepsOn" -> {
115→                            val on = value as Boolean
116→                            if (on) {
117→                                val steps = convertToJSON(values["steps"]!!)
118→                                if (steps!!.length() > 0) {
119→                                    deck.put("delays", steps)
120→                                }
121→                            } else {
122→                                deck.put("delays", JSONObject.NULL)
123→                            }
124→                        }
125→                        "steps" -> {
126→                            deck.put("delays", convertToJSON((value as String)))
127→                        }
128→                        "preset" -> {
129→                            val i: Int = (value as String).toInt()
130→                            if (i > 0) {
131→                                val presetValues = JSONObject(dynExamples[i]!!)
132→                                val arr = presetValues.names() ?: continue
133→                                for (name in arr.stringIterable()) {
134→                                    if ("steps" == name) {
135→                                        update.put("stepsOn", true)
136→                                    }
137→                                    if ("resched" == name) {
138→                                        update.put(name, presetValues.getBoolean(name))
139→                                        values[name] = java.lang.Boolean.toString(presetValues.getBoolean(name))
140→                                    } else {
141→                                        update.put(name, presetValues.getString(name))
142→                                        values[name] = presetValues.getString(name)
143→                                    }
144→                                }
145→                                update.put("preset", "0")
146→                                commit()
147→                            }
148→                        }
149→                    }
150→                }
151→
152→                // save deck
153→                try {
154→                    col.decks.save(deck)
155→                } catch (e: RuntimeException) {
156→                    Timber.e(e, "RuntimeException on saving deck")
157→                    CrashReportService.sendExceptionReport(e, "FilteredDeckOptionsSaveDeck")
158→                    setResult(DeckPicker.RESULT_DB_ERROR)
159→                    finish()
160→                }
161→
162→                // make sure we refresh the parent cached values
163→                cacheValues()
164→                updateSummaries()
165→
166→                // and update any listeners
167→                for (listener in listeners) {
168→                    listener.onSharedPreferenceChanged(this@DeckPreferenceHack, null)
169→                }
170→                return true
171→            }
172→        }
173→
174→        override fun edit(): Editor {
175→            return Editor()
176→        }
177→
178→        init {
179→            cacheValues()
180→        }
181→    }
