185→    override fun onCreate(savedInstanceState: Bundle?) {
186→        Themes.setTheme(this)
187→        Themes.setLegacyActionBar(this)
188→        super.onCreate(savedInstanceState)
189→        UsageAnalytics.sendAnalyticsScreenView(this)
190→        if (!isColInitialized()) {
191→            return
192→        }
193→        val extras = intent.extras
194→        deck = if (extras != null && extras.containsKey("did")) {
195→            col.decks.get(extras.getLong("did"))
196→        } else {
197→            null
198→        } ?: col.decks.current()
199→        registerExternalStorageListener()
200→        if (deck.isNormal) {
201→            Timber.w("Deck is not a dyn deck")
202→            finish()
203→            return
204→        } else {
205→            pref = DeckPreferenceHack()
206→            pref.registerOnSharedPreferenceChangeListener(this)
