229→    @Suppress("deprecation") // Tracked as #5019 on github: addPreferencesFromResource
230→    private fun addPreferences(col: Collection) {
231→        addPreferencesFromResource(R.xml.cram_deck_options)
232→        if (col.schedVer() != 1) {
233→            Timber.d("sched v2: removing filtered deck custom study steps")
234→            // getPreferenceScreen.removePreference didn't return true, so remove from the category
235→            setupSecondFilterListener()
236→            val category = findPreference("studyOptions") as PreferenceCategory
237→            removePreference(category, "stepsOn")
238→            removePreference(category, "steps")
239→        }
240→    }
241→
242→    @Suppress("deprecation") // Tracked as #5019 on github: findPreference
243→    private fun removePreference(category: PreferenceCategory?, key: String) {
244→        val preference = findPreference(key)
245→        if (category == null || preference == null) {
246→            Timber.w("Failed to remove preference '%s'", key)
247→            return
248→        }
249→        val result = category.removePreference(preference)
250→        if (!result) {
251→            Timber.w("Failed to remove preference '%s'", key)
252→        }
253→    }
254→
255→    override fun closeWithResult() {
256→        if (prefChanged) {
257→            // Rebuild the filtered deck if a setting has changed
258→            try {
259→                col.sched.rebuildDyn(deck.getLong("id"))
260→            } catch (e: JSONException) {
261→                Timber.e(e)
262→            }
263→        }
264→        finish()
265→    }
266→
267→    @Suppress("deprecation") // conversion to fragments tracked in github as #5019
268→    override fun updateSummaries() {
269→        allowCommit = false
270→        // for all text preferences, set summary as current database value
271→        val keys: Set<String> = pref.values.keys
272→        for (key in keys) {
273→            val pref = findPreference(key)
274→            val value: String? = if (pref == null) {
275→                continue
276→            } else if (pref is CheckBoxPreference) {
277→                continue
278→            } else if (pref is ListPreference) {
279→                val entry = pref.entry
280→                entry?.toString() ?: ""
281→            } else {
282→                this.pref.getString(key, "")
283→            }
284→            // update value for EditTexts
285→            if (pref is EditTextPreference) {
286→                pref.text = value
287→            }
288→            // update summary
289→            if (!this.pref.summaries.containsKey(key)) {
290→                val s = pref.summary
291→                this.pref.summaries[key] = if (s != null) pref.summary.toString() else null
292→            }
293→            val summ = this.pref.summaries[key]
294→            if (summ != null && summ.contains("XXX")) {
295→                pref.summary = summ.replace("XXX", value!!)
296→            } else {
297→                pref.summary = value
298→            }
299→        }
300→        allowCommit = true
301→    }
302→
303→    @Suppress("deprecation") // Tracked as #5019 on github
304→    private fun buildLists() {
305→        val newOrderPref = findPreference("order") as ListPreference
306→        val newOrderPrefSecond = findPreference("order_2") as ListPreference
307→        newOrderPref.setEntries(R.array.cram_deck_conf_order_labels)
308→        newOrderPref.setEntryValues(R.array.cram_deck_conf_order_values)
309→        newOrderPref.value = pref.getString("order", "0")
310→        newOrderPrefSecond.setEntries(R.array.cram_deck_conf_order_labels)
311→        newOrderPrefSecond.setEntryValues(R.array.cram_deck_conf_order_values)
312→        if (pref.secondFilter) {
313→            newOrderPrefSecond.value = pref.getString("order_2", "5")
314→        }
315→    }
316→
317→    @Suppress("deprecation")
318→    private fun setupSecondFilterListener() {
319→        val secondFilterSign = findPreference("filterSecond") as CheckBoxPreference
320→        val secondFilter = findPreference("secondFilter") as PreferenceCategory
321→        if (pref.secondFilter) {
322→            secondFilter.isEnabled = true
323→            secondFilterSign.isChecked = true
324→        }
325→        secondFilterSign.onPreferenceChangeListener = Preference.OnPreferenceChangeListener { _: Preference?, newValue: Any? ->
326→            if (newValue !is Boolean) {
327→                return@OnPreferenceChangeListener true
328→            }
329→            if (!newValue) {
330→                deck.getJSONArray("terms").remove(1)
331→                secondFilter.isEnabled = false
332→            } else {
333→                secondFilter.isEnabled = true
334→                /**Link to the defaults used in AnkiDesktop
335→                 * <https://github.com/ankitects/anki/blob/1b15069b248a8f86f9bd4b3c66a9bfeab8dfb2b8/qt/aqt/filtered_deck.py#L148-L149>
336→                 */
337→                val narr = JSONArray(listOf("", 20, 5))
338→                deck.getJSONArray("terms").put(1, narr)
339→                val newOrderPrefSecond = findPreference("order_2") as ListPreference
340→                newOrderPrefSecond.value = "5"
341→            }
342→            true
343→        }
344→    }
345→}
