 54→    inner class DeckPreferenceHack : AppCompatPreferenceActivity<FilteredDeckOptions.DeckPreferenceHack>.AbstractPreferenceHack() {
 55→        var secondFilter = false
 56→        override fun cacheValues() {
 57→            Timber.d("cacheValues()")
 58→            val ar = deck.getJSONArray("terms").getJSONArray(0)
 59→            secondFilter = deck.getJSONArray("terms").length() > 1
 60→            val ar2: JSONArray?
 61→            values["search"] = ar.getString(0)
