 67→                values["limit_2"] = ar2.getString(1)
 68→                values["order_2"] = ar2.getString(2)
 69→            }
 70→            val delays = deck.optJSONArray("delays")
 71→            if (delays != null) {
 72→                values["steps"] = convertFromJSON(delays)
 73→                values["stepsOn"] = java.lang.Boolean.toString(true)
 74→            } else {
 75→                values["steps"] = "1 10"
