 79→        }
 80→
 81→        inner class Editor : AppCompatPreferenceActivity<FilteredDeckOptions.DeckPreferenceHack>.AbstractPreferenceHack.Editor() {
 82→            override fun commit(): Boolean {
 83→                Timber.d("commit() changes back to database")
 84→                for ((key, value) in update.valueSet()) {
 85→                    Timber.i("Change value for key '%s': %s", key, value)
 86→                    val ar = deck.getJSONArray("terms")
 87→                    if (pref.secondFilter) {
 88→                        when (key) {
 89→                            "search_2" -> {
 90→                                ar.getJSONArray(1).put(0, value)
 91→                            }
 92→                            "limit_2" -> {
 93→                                ar.getJSONArray(1).put(1, value)
 94→                            }
 95→                            "order_2" -> {
 96→                                ar.getJSONArray(1).put(2, (value as String).toInt())
 97→                            }
 98→                        }
 99→                    }
100→                    when (key) {
101→                        "search" -> {
102→                            ar.getJSONArray(0).put(0, value)
103→                        }
104→
105→                        "limit" -> {
106→                            ar.getJSONArray(0).put(1, value)
107→                        }
108→                        "order" -> {
109→                            ar.getJSONArray(0).put(2, (value as String).toInt())
110→                        }
111→                        "resched" -> {
112→                            deck.put("resched", value)
113→                        }
114→                        "stepsOn" -> {
115→                            val on = value as Boolean
116→                            if (on) {
117→                                val steps = convertToJSON(values["steps"]!!)
118→                                if (steps!!.length() > 0) {
119→                                    deck.put("delays", steps)
120→                                }
121→                            } else {
122→                                deck.put("delays", JSONObject.NULL)
123→                            }
124→                        }
125→                        "steps" -> {
126→                            deck.put("delays", convertToJSON((value as String)))
127→                        }
128→                        "preset" -> {
129→                            val i: Int = (value as String).toInt()
130→                            if (i > 0) {
131→                                val presetValues = JSONObject(dynExamples[i]!!)
132→                                val arr = presetValues.names() ?: continue
133→                                for (name in arr.stringIterable()) {
134→                                    if ("steps" == name) {
135→                                        update.put("stepsOn", true)
136→                                    }
137→                                    if ("resched" == name) {
138→                                        update.put(name, presetValues.getBoolean(name))
139→                                        values[name] = java.lang.Boolean.toString(presetValues.getBoolean(name))
140→                                    } else {
141→                                        update.put(name, presetValues.getString(name))
142→                                        values[name] = presetValues.getString(name)
143→                                    }
144→                                }
145→                                update.put("preset", "0")
146→                                commit()
147→                            }
148→                        }
149→                    }
150→                }
151→
152→                // save deck
153→                try {
154→                    col.decks.save(deck)
155→                } catch (e: RuntimeException) {
156→                    Timber.e(e, "RuntimeException on saving deck")
157→                    CrashReportService.sendExceptionReport(e, "FilteredDeckOptionsSaveDeck")
158→                    setResult(DeckPicker.RESULT_DB_ERROR)
159→                    finish()
160→                }
161→
162→                // make sure we refresh the parent cached values
163→                cacheValues()
164→                updateSummaries()
165→
166→                // and update any listeners
167→                for (listener in listeners) {
168→                    listener.onSharedPreferenceChanged(this@DeckPreferenceHack, null)
169→                }
170→                return true
171→            }
172→        }
